(window.webpackJsonp=window.webpackJsonp||[]).push([[258],{885:function(n,r){n.exports='\x3c!-- \r\ntitle: 05-C与汇编\r\nsort: \r\n--\x3e \r\n# C与汇编\r\n\r\n## 第一个C汇编程序\r\n\r\n```c\r\n#include "stdafx.h"\r\n\r\nint add(int x, int y)\r\n{\r\n\treturn x+y;\r\n}\r\n\r\nint main(int argc, char* argv[])\r\n{\r\n\tadd(1,2);\r\n\treturn 0;\r\n}\r\n```\r\n\r\n### 转为汇编\r\n\r\n```assembly\r\nPUSH 2\r\nPUSH 1\r\nCALL 0040100A\r\n\r\nPUSH EBP\t; 将栈底地址push\r\nMOV EBP,ESP\t; ESP提升至EBP\r\nSUB ESP,40\t; 将栈顶提升0x40h\r\nPUSH EBX\t; 保护现场\r\nPUSH ESI\r\nPUSH EDI\r\n\r\nLEA EDI,DWORD PTR SS:[EBP-40]\t; 将ESP所在地址传入EDI中\r\nMOV ECX,10\t; 设置循环次数为16\r\nMOV EAX,CCCCCCCC\r\nREP STOS DWORD PTR ES:[EDI]\t\t; 开始填充缓冲区\r\n\r\nMOV EAX,DWORD PTR SS:[EBP+8]\t; 拿出数据\r\nADD EAX,DWORD PTR SS:[EBP+C]\t\t\r\n\r\nPOP EDI\t\t; 恢复现场                      \r\nPOP ESI\r\nPOP EBX\r\nMOV ESP,EBP\t; ESP下降回原点\r\nPOP EBP\t\t; EBP返回原点\r\nRETN\t\t; 拿出EIP\r\n```\r\n\r\n## 函数与汇编\r\n\r\n```c\r\nvoid __declspec(naked) func(){}\t\t// 裸函数,不可调用\r\nvoid __declspec(naked) func1(){\t\t// 自己写汇编\r\n    __asm{\r\n\t\tpush ebp\r\n\t\tmov ebp,esp\r\n\t\tsub esp,0x40\r\n\r\n\t\tpush ebx\r\n\t\tpush esi\r\n\t\tpush edi\r\n\r\n\t\tmov eax,0xCCCCCCCC\r\n\t\tmov ecx,0x10\r\n\t\tlea edi,dword ptr ds:[ebp-0x40]\r\n\t\trep stosd\r\n\r\n\t\tmov eax,dword ptr ds:[ebp+8]\r\n\t\tadd eax,dword ptr ds:[ebp+0xC]\r\n\r\n\t\tpop edi\r\n\t\tpop esi\r\n\t\tpop ebx\r\n\r\n\t\tmov esp,ebp\r\n\t\tpop ebp\r\n\r\n        ret\r\n    }\r\n}\r\n```\r\n\r\n### 调用约定\r\n\r\n| 调用约定    | 压栈顺序                     | 平衡堆栈               |\r\n| ----------- | ---------------------------- | ---------------------- |\r\n| \\__cdec     | （默认）                     | 调用者清理栈           |\r\n| \\__stdcall  | 右至左                       | 自身清理堆栈（内平栈） |\r\n| \\__fastcall | edx与ecx存值（超过俩则push） | 无需平栈（内平栈）     |\r\n\r\n## C的数据类型\r\n\r\n- 基本类型\r\n\r\n  > 整数类型\r\n  >\r\n  > - char--byte\r\n  > - short--word\r\n  > - int--dword\r\n  > - long\r\n  > - unsigned--(默认为int)\r\n  >\r\n  > 浮点类型\r\n  >\r\n  > - float\r\n  >\r\n  >   > 小数转二进制\r\n  >   >\r\n  >   > 不断乘2，直到结果为1\r\n  >\r\n  >   小数点左移到高位为1\r\n  >\r\n  >   `8.25`\r\n  >\r\n  >   | 符号位1 | 指数位8    | 有效数字23         |\r\n  >   | ------- | ---------- | ------------------ |\r\n  >   | 0       | 100 0001 0 | 000 1000 0000 0000 |\r\n  >\r\n  >   `0.25`\r\n  >\r\n  >   | 符号位1 | 指数位8    | 有效数字23         |\r\n  >   | ------- | ---------- | ------------------ |\r\n  >   | 0       | 011 1110 1 | 000 0000 0000 0000 |\r\n\r\n- 构造类型\r\n\r\n- 指针类型\r\n\r\n- 空类型\r\n\r\n### 基本类型的汇编\r\n\r\n- `char i = 0xFF;`\r\n\r\n  > `MOV byte ptr [ebp-4],0FFh`\r\n\r\n- `int i = 0xFFFF;`\r\n\r\n  > `MOV dword ptr [ebp-8],0FFFFh`'}}]);